import styles from './FigureEditor.module.css'

function FigureEditor({ doubleClickedObjId, setDoubleClickedObjId, objects, setObjects }) {
    function newColor(color) {
        setObjects(
            objects.map((el) =>
                el.id === doubleClickedObjId ? { ...el, color: color } : el,
            ),
        );
    }

    function newShape() {
        function doShape(radius) {
            setObjects(
                objects.map((el) =>
                    el.id === doubleClickedObjId
                        ? { ...el, radius: radius }
                        : el,
                ),
            );
        }
        if (selectedObject.radius === '50%') {
            doShape('5%');
        } else {
            doShape('50%');
        }
    }

    function deleteFigure() {
        setDoubleClickedObjId("")
        setObjects(objects.filter((el) => el.id !== doubleClickedObjId))
    }

    const selectedObject = objects.find((el) => el.id === doubleClickedObjId);

    const buttons = [
        {
            class: 'colEditGreen',
            color: 'green'
        }
    ]

    return (
        <div className={styles.editObj}>
            <h2>Figure editor</h2>
            <div className={styles.editColor}>
                <div className={styles.editColorButtons}>
                    <button
                        className="colEditGreen"
                        onClick={() => newColor('green')}
                    />
                    <button
                        className="colEditBlue"
                        onClick={() => newColor('blue')}
                    />
                    <button
                        className="colEditYellow"
                        onClick={() => newColor('yellow')}
                    />
                    <button
                        className="colEditGrey"
                        onClick={() => newColor('grey')}
                    />
                    <button
                        className="colEditWhite"
                        onClick={() => newColor('white')}
                    />
                    <button
                        className="colEditPurple"
                        onClick={() => newColor('purple')}
                    />
                    <button
                        className="colEditCyan"
                        onClick={() => newColor('cyan')}
                    />
                    <button
                        className="colEditLime"
                        onClick={() => newColor('lime')}
                    />
                    <button
                        className="colEditRed"
                        onClick={() => newColor('red')}
                    />
                    <button
                        className="colEditBrown"
                        onClick={() => newColor('brown')}
                    />
                    <button
                        className="colEditOrange"
                        onClick={() => newColor('orange')}
                    />
                    <button
                        className="colEditLightBlue"
                        onClick={() => newColor('lightblue')}
                    />
                    <button
                        className="colEditPink"
                        onClick={() => newColor('pink')}
                    />
                    <button
                        className="colEditDarkStaleGrey"
                        onClick={() => newColor('darkslategrey')}
                    />
                </div>
                <p className={styles.objPropName}>
                    {selectedObject.color.charAt(0).toUpperCase() +
                        selectedObject.color.slice(1)}
                </p>
            </div>
            <div className={styles.editButtonForm}>
                <button
                    className="objForm"
                    onClick={newShape}
                    style={{
                        backgroundColor: selectedObject.color,
                        borderRadius: selectedObject.radius,
                    }}
                />
                <p className={styles.objPropName}>
                    {selectedObject.radius === '50%' ? 'Circle' : 'Square'}
                </p>
            </div>
            <button className={styles.deleteFigure} onClick={deleteFigure}>Delete figure</button>
        </div>
    );
}

export default FigureEditor;
